const SYNC_ENDPOINTS = {
  shopify: 'https://api.katalync.com/webhook/shopify-sync-pull',
  woocommerce: 'https://api.katalync.com/webhook/woocommerce-sync-pull',
  prestashop: 'https://api.katalync.com/webhook/prestashop-sync-pull'
};

const response = $input.first().json;
const vendors = Array.isArray(response) ? response : [];

if (vendors.length === 0) {
  return [{ json: { done: true, vendor_count: 0, message: 'No vendors due for sync' } }];
}

const results = [];

for (const vendor of vendors) {
  const source = vendor.source || 'manual';
  const endpoint = SYNC_ENDPOINTS[source];

  if (!endpoint) {
    results.push({
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: source,
      sync_success: false,
      skipped: true,
      message: 'No sync endpoint for source: ' + source
    });
    continue;
  }

  try {
    const syncResp = await httpReq(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: SYSTEM_SYNC_SECRET,
        vendor_id: vendor.id
      })
    });

    let syncData = {};
    try { syncData = await syncResp.json(); } catch (e) { syncData = { raw: await syncResp.text() }; }

    const syncInterval = vendor.sync_interval_hours || 24;
    const now = new Date();
    const nextSyncAt = new Date(now.getTime() + syncInterval * 60 * 60 * 1000).toISOString();

    await httpReq(SUPABASE_URL + '/vendors?id=eq.' + vendor.id, {
      method: 'PATCH',
      headers: sbHeaders,
      body: JSON.stringify({
        last_sync_at: now.toISOString(),
        next_sync_at: nextSyncAt,
        sync_status: syncResp.ok && syncData.success ? 'synced' : 'error',
        updated_at: now.toISOString()
      })
    });

    await httpReq(SUPABASE_URL + '/sync_logs', {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        vendor_id: vendor.id,
        direction: 'pull',
        sync_type: 'scheduled',
        status: syncResp.ok && syncData.success ? 'completed' : 'failed',
        total_products: syncData.total || 0,
        created_products: syncData.created || 0,
        updated_products: syncData.updated || 0,
        error_count: syncData.errors || 0,
        details: { source: source, scheduled: true, response: syncData },
        started_at: now.toISOString(),
        completed_at: new Date().toISOString()
      })
    });

    if (!syncResp.ok || !syncData.success) {
      await httpReq(SUPABASE_URL + '/notifications', {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          vendor_id: vendor.id,
          type: 'sync_error',
          title: 'Scheduled Sync Failed: ' + (vendor.name || source),
          message: syncData.error || 'Scheduled sync returned an error. Check configuration.',
          severity: 'error',
          read: false,
          created_at: new Date().toISOString()
        })
      });
    }

    results.push({
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: source,
      sync_success: syncResp.ok && syncData.success,
      total: syncData.total || 0,
      error: syncData.error || null
    });

  } catch (err) {
    try {
      const syncInterval = vendor.sync_interval_hours || 24;
      const now = new Date();
      const nextSyncAt = new Date(now.getTime() + syncInterval * 60 * 60 * 1000).toISOString();
      await httpReq(SUPABASE_URL + '/vendors?id=eq.' + vendor.id, {
        method: 'PATCH',
        headers: sbHeaders,
        body: JSON.stringify({
          sync_status: 'error',
          next_sync_at: nextSyncAt,
          updated_at: now.toISOString()
        })
      });
      await httpReq(SUPABASE_URL + '/notifications', {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          vendor_id: vendor.id,
          type: 'sync_error',
          title: 'Scheduled Sync Failed: ' + (vendor.name || source),
          message: err.message,
          severity: 'error',
          read: false,
          created_at: new Date().toISOString()
        })
      });
    } catch (e) {}

    results.push({
      vendor_id: vendor.id,
      vendor_name: vendor.name,
      source: source,
      sync_success: false,
      error: err.message
    });
  }
}

return [{ json: {
  done: true,
  vendor_count: vendors.length,
  results: results,
  timestamp: new Date().toISOString()
} }];

